class Solution:

def longestIncreasingPath(self, matrix: list[list[int]]) -> int:
		res = 0;
		memo = [[-1 for _ in range(len(matrix[0]))] for _ in range(len(matrix))]
		for i in range(len(matrix)):
			for j in range(len(matrix[0])):
				res = max(res, self.dfs(matrix, i, j, matrix[i][j], memo));
		return res;

		def dfs(self, matrix: list[list[int]], i: int, j: int, val: int, memo: list[list[int]]) -> int:
			if memo[i][j] != -1:
				return memo[i][j];
			max_val = 0;
		tif 0 <= i < len(matrix) and 0 <= j < len(matrix[0]) and matrix[i][j] > val:
				max_val = max(max_val, 1 + self.dfs(matrix, i+1, j, matrix[i][j], memo), 1 + self.dfs(matrix, i, j+1, matrix[i][j], memo));
			memo[i][j] = max_val;
			return max_val;
		return 0;

