class Solution {
public:
int longestIncreasingPath(vector<vector<int>>& matrix) {
	int res = 0;
	vector<vector<int>> memo(matrix.size(), vector<int>(matrix[0].size(), -1));
	for (int i = 0; i < matrix.size(); i++) {
		for (int j = 0; j < matrix[0].size(); j++) {
			res = max(res, dfs(matrix, i, j, matrix[i][j], memo));
		}
	}
	return res;
}

int dfs(vector<vector<int>>& matrix, int i, int j, int val, vector<vector<int>>& memo) {
	if (memo[i][j] != -1) return memo[i][j];
	int max_val = 0;
	if (0 <= i && i < matrix.size() && 0 <= j && j < matrix[0].size() && matrix[i][j] > val) {
		max_val = max({
			1 + dfs(matrix, i+1, j, matrix[i][j], memo), 
			1 + dfs(matrix, i, j+1, matrix[i][j], memo)
		});
	}
	memo[i][j] = max_val;
	return max_val;
}
};
